data.query:
mutation UpdateMetaobject($id: ID!, $metaobject: MetaobjectUpdateInput!) {
    metaobjectUpdate(id: $id, metaobject: $metaobject) {
        metaobject {
            id
            handle
            type
            displayName
            updatedAt
            fields {
                key
                value
            }
        }
        userErrors {
            field
            message
            code
        }
    }
}
